    @Test
    @DisplayName("TC19: parse(URL, timeout) for unsupported mime type throws UnsupportedMimeTypeException")
    public void test_TC19() throws Exception {
        int port = 8089;
        SimpleHttpServer srv = new SimpleHttpServer(port, 200, "PDFDATA", "application/pdf");
        srv.start();
        srv.awaitReady();
        URL url = new URL("http://localhost:" + port + "/file.pdf");
        assertThrows(org.jsoup.UnsupportedMimeTypeException.class, () -> Jsoup.parse(url, 1000));
    }

    // helper to concat byte arrays
    private static byte[] concat(byte[] a, byte[] b) {
        byte[] c = new byte[a.length + b.length];
        System.arraycopy(a, 0, c, 0, a.length);
        System.arraycopy(b, 0, c, a.length, b.length);
        return c;
    }
